import { NextResponse } from "next/server";

import { getOrdersRepository } from "@/lib/orders/factory";
import { type NewOrder } from "@/types/orders";

const repository = getOrdersRepository();

export async function GET() {
	try {
		const orders = await repository.getOrders();
		return NextResponse.json(orders, { status: 200 });
	} catch (error) {
		console.error(error);
		return NextResponse.json({ error: "Failed to read orders" }, { status: 500 });
	}
}

export async function POST(request: Request) {
	try {
		const payload = (await request.json()) as NewOrder;
		const newOrder = await repository.createOrder(payload);
		return NextResponse.json(newOrder, { status: 201 });
	} catch (error) {
		console.error(error);
		return NextResponse.json({ error: "Failed to create order" }, { status: 500 });
	}
}


